import { lbsToKgs, kgsToLbs } from "lib/unitConverters";

describe("Unit Conversion", () => {
  test.each`
    lbs     | kgs
    ${2.2}  | ${0.9979044007584075}
    ${1}    | ${0.45359290943563974}
    ${-1}   | ${-0.45359290943563974}
    ${-2.2} | ${-0.9979044007584075}
    ${0}    | ${0}
  `("$lbs lbs is $kgs kgs (tested both ways)", ({ lbs, kgs }) => {
    expect(lbsToKgs(lbs)).toBe(kgs);
    expect(kgsToLbs(kgs)).toBe(lbs);
  });
});
